INSERT INTO xeus.mon_evet_hist( usvc_outb_id, evt_svc_nm, evt_typ, evt_typ_cd, msg_typ_cd, evt_nm, evt_cntn, outb_pos_nm, outb_posx, outb_posy, evt_outb_dtm, evt_clr_dtm, evt_proc_cd, evt_actn_dtm, evt_actn_usrid, evt_actn_cntn, test_yn, evt_json,
_geometry ) VALUES ( #{usvcOutbId}, #{evtSvcNm}, #{evtTyp}, #{evtTypCd}, #{msgTypCd}, #{evtNm}, #{evtCntn}, #{outbPosNm}, #{outbPosx}::numeric, #{outbPosy}::numeric, #{evtOutbDtm}, #{evtClrDtm}, #{evtProcCd}, #{evtActnDtm}, #{evtActnUsrid}, #{evtActnCntn}, #{testYn}, #{evtJson},
(select st_transform(st_setsrid(st_makepoint(#{outbPosx}::numeric, #{outbPosy}::numeric), 4326), 5186)) );

mapper.update:
UPDATE xeus.mon_evet_hist SET

		usvc_outb_id = #{usvcOutbId}


		, evt_svc_nm = #{evtSvcNm}




		, evt_typ = #{evtTyp}




		, evt_typ_cd = #{evtTypCd}




		, msg_typ_cd = #{msgTypCd}




		, evt_nm = #{evtNm}




		, evt_cntn = #{evtCntn}




		, outb_pos_nm = #{outbPosNm}




		, outb_posx = #{outbPosx}::numeric




		, outb_posy = #{outbPosy}::numeric




		, evt_outb_dtm = #{evtOutbDtm}




		, evt_clr_dtm = #{evtClrDtm}




		, evt_proc_cd = #{evtProcCd}




		, evt_actn_dtm = #{evtActnDtm}




		, evt_actn_usrid = #{evtActnUsrid}




		, evt_actn_cntn = #{evtActnCntn}




		, test_yn = #{testYn}




		, evt_json = #{evtJson}


	, _geometry = (select st_transform(st_setsrid(st_makepoint(#{outbPosx}::numeric, #{outbPosy}::numeric), 4326), 5186))

WHERE usvc_outb_id = #{usvcOutbId}
